    41	int tun_alloc(const char *dev)
    42	{
    43	  struct ifreq ifr;
    44	  int fd, err;
    45	
    46	  if ((fd = open("/dev/net/tun", O_RDWR)) < 0) {
    47	    LOG_E(UTIL, "failed to open /dev/net/tun\n");
    48	    return -1;
    49	  }
    50	
    51	  memset(&ifr, 0, sizeof(ifr));
    52	  /* Flags: IFF_TUN   - TUN device (no Ethernet headers)
    53	   *        IFF_TAP   - TAP device
    54	   *
    55	   *        IFF_NO_PI - Do not provide packet information
    56	   */
    57	  ifr.ifr_flags = IFF_TUN | IFF_NO_PI;
    58	  strncpy(ifr.ifr_name, dev, sizeof(ifr.ifr_name) - 1);
    59	  if ((err = ioctl(fd, TUNSETIFF, (void *)&ifr)) < 0) {
    60	    close(fd);
    61	    return err;
    62	  }
    63	  // According to https://www.kernel.org/doc/Documentation/networking/tuntap.txt, TUNSETIFF performs string
    64	  // formatting on ifr_name. To ensure that the generated name is what we expect, check it here.
    65	  AssertFatal(strcmp(ifr.ifr_name, dev) == 0, "Failed to create tun interface, expected ifname %s, got %s\n", dev, ifr.ifr_name);
    66	
    67	  err = fcntl(fd, F_SETFL, O_NONBLOCK);
    68	  if (err == -1) {
    69	    close(fd);
    70	    LOG_E(UTIL, "Error fcntl (%d:%s)\n", errno, strerror(errno));
    71	    return err;
    72	  }
    73	
    74	  return fd;
