   110	/*
   111	 * \brief set a genneric interface parameter
   112	 * \param ifn the name of the interface to modify
   113	 * \param if_addr the address that needs to be modified
   114	 * \param operation one of SIOCSIFADDR (set interface address), SIOCSIFNETMASK
   115	 *   (set network mask), SIOCSIFBRDADDR (set broadcast address), SIOCSIFFLAGS
   116	 *   (set flags)
   117	 * \return true on success, false otherwise
   118	 */
   119	static bool setInterfaceParameter(int sock_fd, const char *ifn, int af, const char *if_addr, int operation)
   120	{
   121	  DevAssert(af == AF_INET || af == AF_INET6);
   122	  struct ifreq ifr = {0};
   123	  strncpy(ifr.ifr_name, ifn, sizeof(ifr.ifr_name) - 1);
   124	  struct in6_ifreq ifr6 = {0};
   125	
   126	  void *ioctl_opt = NULL;
   127	  if (af == AF_INET) {
   128	    struct sockaddr_in addr = {.sin_family = AF_INET};
   129	    int ret = inet_pton(af, if_addr, &addr.sin_addr);
   130	    if (ret != 1) {
   131	      LOG_E(OIP, "inet_pton(): cannot convert %s to IPv4 network address\n", if_addr);
   132	      return false;
   133	    }
   134	    memcpy(&ifr.ifr_ifru.ifru_addr,&addr,sizeof(struct sockaddr_in));
   135	    ioctl_opt = &ifr;
   136	  } else {
   137	    struct sockaddr_in6 addr6 = {.sin6_family = AF_INET6};
   138	    int ret = inet_pton(af, if_addr, &addr6.sin6_addr);
   139	    if (ret != 1) {
   140	      LOG_E(OIP, "inet_pton(): cannot convert %s to IPv6 network address\n", if_addr);
   141	      return false;
   142	    }
   143	    memcpy(&ifr6.ifr6_addr, &addr6.sin6_addr, sizeof(struct in6_addr));
   144	    // we need to get the if index to put it into ifr6
   145	    if (ioctl(sock_fd, SIOGIFINDEX, &ifr) < 0) {
   146	      LOG_E(OIP, "ioctl() failed: errno %d, %s\n", errno, strerror(errno));
   147	      return false;
   148	    }
   149	    ifr6.ifr6_ifindex = ifr.ifr_ifindex;
   150	    ifr6.ifr6_prefixlen = 64;
   151	    ioctl_opt = &ifr6;
   152	  }
   153	
   154	  bool success = ioctl(sock_fd, operation, ioctl_opt) == 0;
   155	  if (!success)
   156	    LOG_E(OIP, "Setting operation %d for %s: ioctl call failed: %d, %s\n", operation, ifn, errno, strerror(errno));
   157	  return success;
   158	}
