   161	typedef enum { INTERFACE_DOWN, INTERFACE_UP } if_action_t;
   162	/*
   163	* \brief bring interface up (up != 0) or down (up == 0)
   164	*/
   165	static bool change_interface_state(int sock_fd, const char *ifn, if_action_t if_action)
   166	{
   167	  const char *action = if_action == INTERFACE_DOWN ? "DOWN" : "UP";
   168	
   169	  struct ifreq ifr = {0};
   170	  strncpy(ifr.ifr_name, ifn, sizeof(ifr.ifr_name) - 1);
   171	
   172	  /* get flags of this interface: see netdevice(7) */
   173	  bool success = ioctl(sock_fd, SIOCGIFFLAGS, (caddr_t)&ifr) == 0;
   174	  if (!success && if_action == INTERFACE_DOWN && errno == ENODEV) {
   175	    LOG_W(OIP, "trying to remove non-existant device %s\n", ifn);
   176	    return true;
   177	  }
   178	  LOG_D(OIP, "Got flags for %s: 0x%x (action: %s)\n", ifn, ifr.ifr_flags, action);
   179	
   180	  if (if_action == INTERFACE_UP) {
   181	    ifr.ifr_flags |= IFF_UP | IFF_NOARP | IFF_POINTOPOINT;
   182	    ifr.ifr_flags &= ~IFF_MULTICAST;
   183	  } else {
   184	    ifr.ifr_flags &= ~IFF_UP;
   185	  }
   186	
   187	  success = ioctl(sock_fd, SIOCSIFFLAGS, (caddr_t)&ifr) == 0;
   188	  if (!success)
   189	    goto fail_interface_state;
   190	  LOG_D(OIP, "Interface %s successfully set %s\n", ifn, action);
   191	
   192	  return true;
   193	
   194	fail_interface_state:
   195	  LOG_E(OIP, "Bringing interface %s for %s: ioctl call failed: %d, %s\n", action, ifn, errno, strerror(errno));
   196	  return false;
   197	}
